package genxsolution.vms.vmsbackend.employee_hr_management.ration_distribution.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.employee_hr_management.ration_distribution.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.ration_distribution.service.RationDistributionService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/hr/ration-distributions") public class RationDistributionController { private final RationDistributionService service; public RationDistributionController(RationDistributionService service){this.service=service;} @GetMapping public List<RationDistributionResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public RationDistributionResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public RationDistributionResponse create(@RequestBody RationDistributionUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public RationDistributionResponse update(@PathVariable UUID id,@RequestBody RationDistributionUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
